/** FPSS server connection ack (wire code 4, `StreamMsgType::Connected`). Mirrors `FpssControl::Connected`. Carries no payload. */
export interface Connected {

}

/**
 * FPSS contract identifier. Surfaced on every decoded FPSS data
 * event as `event.quote.contract` / `event.trade.contract` / etc.
 * `secType` is the symbolic uppercase name (`"STOCK"` / `"OPTION"` /
 * `"INDEX"` / `"RATE"`); `right` is `"C"` / `"P"` / `null`;
 * `strikeDollars` is the option strike in dollars, while `strike` is
 * the wire-level integer (thousandths of a dollar).
 */
export interface Contract {
  symbol: string
  secType: string
  expiration?: number
  right?: string
  strikeDollars?: number
  strike?: number
}

/** FPSS server assigned a contract id. Mirrors `FpssControl::ContractAssigned`. The `contract` payload carries the full resolved `Contract` (root, sec_type, expiration / strike / right for options). */
export interface ContractAssigned {
  id: number
  contract: Contract
}

/**
 * Default base URL for the local Terminal's REST surface. Mirrors
 * [`thetadatadx::config::DEFAULT_REST_BASE_URL`]. Exposed as a module-
 * level constant so callers can write
 * `FallbackPolicy.restAlways(DEFAULT_REST_BASE_URL)`
 * instead of repeating the URL literal.
 */
export const DEFAULT_REST_BASE_URL: string

/** FPSS server disconnected the client (wire code 12). Mirrors `FpssControl::Disconnected`. `reason` is the `RemoveReason` discriminant cast to `i32`; compare against `tdbe::types::enums::RemoveReason as i32` for symbolic interpretation. */
export interface Disconnected {
  reason: number
  /**
   * Resolved `RemoveReason` variant name (e.g. `"TooManyRequests"`,
   * `"InvalidCredentials"`, `"Unspecified"` for unknown codes).
   * Derived from the wire-level `reason` integer.
   */
  reasonName: string
}

